class Solution:
    def baseNeg2(self, n: int) -> str:
        if n == 0:
            return "0"
        bits = []
        while n != 0:
            remainder = n % 2
            n = (n - remainder) // (-2)
            bits.append(remainder)
        bits.reverse()
        return ''.join(map(str, bits))

